WHERE id = #{rootId}

mapper.select:
SELECT *
FROM comment
WHERE article_id = #{articleId}
AND parent_id = 0
AND status = '1'

    AND id < #{lastId}

ORDER BY id DESC
LIMIT #{size}

SELECT *
FROM comment
WHERE root_id = #{rootId}
AND parent_id != 0
AND status = '1'

    AND id > #{lastId}

ORDER BY id ASC
LIMIT #{size}
